import test from "node:test";
import assert from "node:assert/strict";

import { JsonSequenceParser } from "../src/json-sequence-parser.mjs";
import { readAuditExport } from "../src/audit-export-reader.mjs";

test("UTF-8 scalars survive arbitrary byte chunk boundaries", async () => {
  const expected = "café ☕ — 東京";
  const bytes = Buffer.from("\x1e" + JSON.stringify({ channel: "intl", sequence: 0, text: expected }) + "\n", "utf8");
  const coffee = bytes.indexOf(Buffer.from("☕", "utf8"));
  const tokyo = bytes.indexOf(Buffer.from("東京", "utf8"));
  const chunks = [
    bytes.subarray(0, coffee + 1),
    bytes.subarray(coffee + 1, tokyo + 2),
    bytes.subarray(tokyo + 2)
  ];

  const result = await readAuditExport(chunks);
  assert.deepEqual(result, { intl: expected });
});

test("incremental parser emits the original scalar rather than replacement text", () => {
  const parser = new JsonSequenceParser();
  const bytes = Buffer.from("\x1e{\"channel\":\"x\",\"sequence\":0,\"text\":\"🙂\"}\n", "utf8");
  const scalar = bytes.indexOf(Buffer.from("🙂", "utf8"));
  parser.push(bytes.subarray(0, scalar + 2));
  parser.push(bytes.subarray(scalar + 2));
  const records = parser.finish();
  assert.equal(records[0].text, "🙂");
});
